#include <omp.h>

void 
findK(	long height,
		knode *knodesD,
		long knodes_elem,
		record *recordsD,

		long *currKnodeD,
		long *offsetD,
		int *keysD, 
		record *ansD,
		int order,
		int count)
{
	// Parallelize over count (bid)
	#pragma omp parallel for
	for (int bid = 0; bid < count; bid++) {
		for(int i = 0; i < height; i++){
			// For each thread id in order
			for (int thid = 0; thid < order; thid++) {
				if((knodesD[currKnodeD[bid]].keys[thid]) <= keysD[bid] && (knodesD[currKnodeD[bid]].keys[thid+1] > keysD[bid])){
